def _parse(tokens, priority = (-1,)):
    result = ''
    nexttok = next(tokens)
    if nexttok == '!':
        result += 'not '
        nexttok = next(tokens)
        if nexttok == '!' or nexttok == '(':
            (sub, nexttok) = _parse(tokens)
            result = '%s(%s)' % (result, sub)
            if nexttok != ')':
                raise ValueError('unbalanced parenthesis in plural form')
    if nexttok == 'n':
        result = '%s%s' % (result, nexttok)
